package com.hospital.management.dao.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import com.hospital.management.util.*;import java.math.*;import java.sql.*;/** Posts one admission ROOM item and recalculates its bill on the caller-owned transaction. */public class AdmissionBillingDaoImpl implements AdmissionBillingDao{private final BillDao bills;private final BillNumberGenerator numbers;private final BillingCalculator calc;public AdmissionBillingDaoImpl(){this(new BillDaoImpl(),new BillNumberGenerator(),new BillingCalculator());}public AdmissionBillingDaoImpl(BillDao b,BillNumberGenerator n,BillingCalculator c){bills=b;numbers=n;calc=c;}public long postRoomCharge(Connection c,Admission a,long days,BigDecimal rate,BigDecimal charge)throws SQLException{if(exists(c,a.getAdmissionId()))throw new SQLException("Admission room charge already exists","23000",1);Long id=findBill(c,a);if(id==null){Bill b=new Bill();b.setBillNumber(numbers.next(c));b.setPatientId(a.getPatientId());b.setAppointmentId(a.getAppointmentId());b.setSubtotal(BigDecimal.ZERO.setScale(2));b.setTaxAmount(BigDecimal.ZERO.setScale(2));b.setDiscountAmount(BigDecimal.ZERO.setScale(2));b.setTotalAmount(BigDecimal.ZERO.setScale(2));b.setPaidAmount(BigDecimal.ZERO.setScale(2));b.setBalanceAmount(BigDecimal.ZERO.setScale(2));b.setStatus("UNPAID");id=bills.createBill(c,b);}try(PreparedStatement s=c.prepareStatement("INSERT INTO BILL_ITEMS(BILL_ID,ADMISSION_ID,ITEM_TYPE,DESCRIPTION,QUANTITY,UNIT_PRICE,LINE_TOTAL)VALUES(?,?,'ROOM',?,?,?,?)")){s.setLong(1,id);s.setLong(2,a.getAdmissionId());s.setString(3,"Room charges for admission "+a.getAdmissionNumber());s.setBigDecimal(4,BigDecimal.valueOf(days).setScale(2));s.setBigDecimal(5,rate.setScale(2,RoundingMode.HALF_UP));s.setBigDecimal(6,charge);s.executeUpdate();}recalculate(c,id);return id;}private boolean exists(Connection c,Long id)throws SQLException{try(PreparedStatement s=c.prepareStatement("SELECT 1 FROM BILL_ITEMS WHERE ADMISSION_ID=?")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){return r.next();}}}private Long findBill(Connection c,Admission a)throws SQLException{String q="SELECT b.BILL_ID FROM BILLS b WHERE b.STATUS='UNPAID' AND b.PAID_AMOUNT=0 AND "+(a.getAppointmentId()!=null?"b.APPOINTMENT_ID=?":"b.PATIENT_ID=?")+" ORDER BY b.BILL_ID DESC FETCH FIRST 1 ROW ONLY FOR UPDATE";try(PreparedStatement s=c.prepareStatement(q)){s.setLong(1,a.getAppointmentId()!=null?a.getAppointmentId():a.getPatientId());try(ResultSet r=s.executeQuery()){return r.next()?r.getLong(1):null;}}}private void recalculate(Connection c,Long id)throws SQLException{BigDecimal sub,tax,discount,paid;try(PreparedStatement s=c.prepareStatement("SELECT NVL((SELECT SUM(LINE_TOTAL) FROM BILL_ITEMS WHERE BILL_ID=b.BILL_ID),0),TAX_AMOUNT,DISCOUNT_AMOUNT,PAID_AMOUNT FROM BILLS b WHERE BILL_ID=? FOR UPDATE")){s.setLong(1,id);try(ResultSet r=s.executeQuery()){if(!r.next())throw new SQLException("Bill not found");sub=r.getBigDecimal(1);tax=r.getBigDecimal(2);discount=r.getBigDecimal(3);paid=r.getBigDecimal(4);}}BigDecimal total=calc.calculateTotal(sub,tax,discount),balance=calc.calculateBalance(total,paid);String status=calc.deriveBillStatus(total,paid,"UNPAID");if(!bills.updateFinancialSummary(c,id,sub,tax,discount,total,paid,balance,status))throw new SQLException("Bill summary update failed");}}
